{
  "parameters": "z.object({ item: z.string().describe("The Minecraft name or display name of the item to equip, e.g., 'leather_chestplate' or 'Leather Tunic'") })",
  "executionArgs": {
    "item": "leather_chestplate"
  },
  "code": "const findTargetItem = function(name) {
  const search = name.toLowerCase().replace(/_/g, ' ');
  return bot.inventory.items().find(function(i) {
    return i.name.toLowerCase() === name.toLowerCase() ||
           i.name.toLowerCase() === name.toLowerCase().replace(/\s+/g, '_') ||
           (i.displayName && i.displayName.toLowerCase() === search);
  });
};
const itemToEquip = findTargetItem(args.item);
if (!itemToEquip) {
  return "<MISSING>: You do not have '" + args.item + "' in your inventory.";
}
let slot = 'hand';
const internalName = itemToEquip.name.toLowerCase();
if (internalName.includes('helmet') || internalName.includes('cap')) {
  slot = 'head';
} else if (internalName.includes('chestplate') || internalName.includes('tunic') || internalName.includes('elytra')) {
  slot = 'torso';
} else if (internalName.includes('leggings') || internalName.includes('pants')) {
  slot = 'legs';
} else if (internalName.includes('boots') || internalName.includes('shoes')) {
  slot = 'feet';
}
try {
  await bot.equip(itemToEquip, slot);
  return "<SUCCESS>: Equipped " + (itemToEquip.displayName || itemToEquip.name) + " to " + slot + ".";
} catch (err) {
  return "<ERROR>: Failed to equip " + itemToEquip.name + ": " + err.message;
}"
}
